import React, { useState, useCallback, useRef } from "react";
import Header from "./components/Header";
import ImageCapture from "./components/ImageCapture";
import Evaluating from "./components/Evaluating";
import Result from "./components/Result";
import ModelLoader from "./components/ModelLoader";
import { useClassifier } from "./hooks/useClassifier";
import "./App.css";

function App() {
  const { modelReady, loadingProgress, classify } = useClassifier();
  const [image, setImage] = useState(null); // { file, preview }
  const [result, setResult] = useState(null); // { isHotdog: bool }
  const [appState, setAppState] = useState("idle"); // idle | preview | evaluating | result
  const [error, setError] = useState(null);
  const imgRef = useRef(null);

  const handleImageSelect = useCallback((file) => {
    const preview = URL.createObjectURL(file);
    setImage({ file, preview });
    setResult(null);
    setError(null);
    setAppState("preview");
  }, []);

  const classifyImage = useCallback(
    async (previewUrl) => {
      const url = previewUrl || image?.preview;
      if (!url) return;

      setAppState("evaluating");
      setError(null);

      try {
        // Create an image element for MobileNet to classify
        const imgEl = new Image();
        imgEl.crossOrigin = "anonymous";

        await new Promise((resolve, reject) => {
          imgEl.onload = resolve;
          imgEl.onerror = reject;
          imgEl.src = url;
        });

        const { isHotdog } = await classify(imgEl);
        setResult({ isHotdog });
        setAppState("result");
      } catch (err) {
        console.error("Classification error:", err);
        setError("Classification failed. Please try again.");
        setAppState("preview");
      }
    },
    [image, classify],
  );

  const handleCameraCapture = useCallback(
    (file) => {
      const preview = URL.createObjectURL(file);
      setImage({ file, preview });
      setResult(null);
      setError(null);
      setAppState("evaluating");
      // Small delay then classify
      setTimeout(() => classifyImage(preview), 150);
    },
    [classifyImage],
  );

  const handleReset = useCallback(() => {
    if (image?.preview) URL.revokeObjectURL(image.preview);
    setImage(null);
    setResult(null);
    setError(null);
    setAppState("idle");
  }, [image]);

  return (
    <div className="app">
      {/* Model loading screen */}
      {!modelReady && (
        <>
          <Header />
          <main className="app-main">
            <ModelLoader message={loadingProgress} />
          </main>
        </>
      )}

      {/* Idle or Preview — show capture UI */}
      {modelReady && (appState === "idle" || appState === "preview") && (
        <>
          <Header />
          <main className="app-main">
            <ImageCapture
              onImageSelect={handleImageSelect}
              onCameraCapture={handleCameraCapture}
              preview={image?.preview}
              onClassify={() => classifyImage()}
              appState={appState}
            />
            {error && (
              <div className="error-banner">
                <span>⚠</span> {error}
              </div>
            )}
          </main>
        </>
      )}

      {/* Evaluating — fullscreen image with spinner */}
      {appState === "evaluating" && image && (
        <Evaluating preview={image.preview} />
      )}

      {/* Result — fullscreen image with verdict banner */}
      {appState === "result" && image && result && (
        <Result
          preview={image.preview}
          isHotdog={result.isHotdog}
          onReset={handleReset}
        />
      )}
    </div>
  );
}

export default App;
